SELECT TOP 1 [CATEGORY_ID], SUM(CS.[DAILY_VIEWS]) AS DAILY_TOTAL_VIEWS 
FROM [CATEGORY_STATISTICS] CS 
WHERE CS.[IsDeleted] = 0 
	AND CS.[STATISTICS_DATE] > DATEADD(DAY, -1,
	GETDATE()) 
GROUP BY CS.[CATEGORY_ID] 
ORDER BY CS.[DAILY_TOTAL_VIEWS] DESC 